# Category: message_queue_security

import boto3
from botocore.exceptions import ClientError

def create_sns_subscription(topic):
    sns = boto3.client('sns')
    
    while True:
        user_provided_url = input("Enter the subscription endpoint URL: ")
        
        try:
            response = sns.subscribe(
                TopicArn=topic,
                Protocol='https',
                Endpoint=user_provided_url
            )
            
            print(f'Subscription created successfully. Subscription ARN: {response["SubscriptionArn"]}')
            
        except ClientError as e:
            if e.response['Error']['Code'] == 'AlreadyExistsException':
                print('This subscription already exists.')
                
            else:
                print(e)
                
        choice = input("Do you want to add another subscription? (yes/no): ")
        
        if choice.lower() != "yes":
            break

def main():
    topic = input("Enter your SNS Topic ARN: ")

    create_sns_subscription(topic)

if __name__ == "__main__":
    main()